export function parseSessionJsonl(text) {
  return text.trim().split('\n').map(line => JSON.parse(line));
}

export function analyzeSession(entries) {
  return {
    entries,
    metrics: {
      assistantTurns: 0,
      totalTokens: 0,
      cost: 0,
      toolCalls: {}
    }
  };
}

export function formatReport(analysis) {
  return 'Session report';
}

