import test from 'node:test';
import assert from 'node:assert/strict';
import { parseSessionJsonl, analyzeSession, formatReport } from './session-inspector.js';

const fixture = [
  '{"type":"session","version":3,"id":"s1","timestamp":"2026-01-01T00:00:00.000Z","cwd":"/tmp/project"}',
  '{"type":"message","id":"u1","parentId":null,"timestamp":"2026-01-01T00:00:01.000Z","message":{"role":"user","content":"fix tests","timestamp":1767225601000}}',
  '{"type":"message","id":"a1","parentId":"u1","timestamp":"2026-01-01T00:00:03.000Z","message":{"role":"assistant","content":[{"type":"toolCall","id":"tc1","name":"read","arguments":{"path":"a.js"}}],"usage":{"input":100,"output":20,"cacheRead":0,"cacheWrite":0,"totalTokens":120,"cost":{"total":0.01}},"stopReason":"toolUse","timestamp":1767225603000}}',
  '{"type":"message","id":"tr1","parentId":"a1","timestamp":"2026-01-01T00:00:04.000Z","message":{"role":"toolResult","toolCallId":"tc1","toolName":"read","content":[{"type":"text","text":"file"}],"isError":false,"timestamp":1767225604000}}',
  '{"type":"message","id":"a2","parentId":"tr1","timestamp":"2026-01-01T00:00:07.000Z","message":{"role":"assistant","content":[{"type":"text","text":"done"}],"usage":{"input":150,"output":30,"cacheRead":10,"cacheWrite":0,"totalTokens":190,"cost":{"total":0.02}},"stopReason":"stop","timestamp":1767225607000}}',
  'not valid json'
].join('\n');

test('parses jsonl while preserving malformed-line diagnostics', () => {
  const parsed = parseSessionJsonl(fixture);
  assert.equal(parsed.entries.length, 5);
  assert.equal(parsed.diagnostics.length, 1);
  assert.equal(parsed.diagnostics[0].line, 6);
});

test('computes useful session metrics', () => {
  const parsed = parseSessionJsonl(fixture);
  const analysis = analyzeSession(parsed.entries);
  assert.equal(analysis.metrics.assistantTurns, 2);
  assert.equal(analysis.metrics.totalTokens, 310);
  assert.equal(analysis.metrics.cost, 0.03);
  assert.equal(analysis.metrics.toolCalls.read, 1);
  assert.equal(analysis.metrics.durationMs, 6000);
});

test('formats a human-readable report with anomalies', () => {
  const parsed = parseSessionJsonl(fixture);
  const report = formatReport(analyzeSession(parsed.entries, parsed.diagnostics));
  assert.match(report, /assistant turns/i);
  assert.match(report, /tokens/i);
  assert.match(report, /malformed/i);
});
